// Accepts email data from Google Apps Script forwarder
// Expected fields: from, subject, body, date, to, cc, threadId
const raw = $json.body || $json;
const from = (raw.from || '').toLowerCase();
const subject = (raw.subject || '').toLowerCase();
const body = (raw.body || raw.text || '').substring(0, 3000);
const date = raw.date || new Date().toISOString();
const threadId = raw.threadId || '';

// Classification rules
let category = 'general';
let agent = null;
let priority = 'Medium';
let tags = [];

// Security advisories
if (from.includes('ncsc') || from.includes('cert.gov') || subject.includes('vulnerability') || subject.includes('security advisory') || subject.includes('threat')) {
  category = 'security-advisory';
  agent = 'security-agent';
  priority = 'High';
  tags.push('security', 'advisory');
}

// IASME / Cyber Essentials
else if (from.includes('iasme') || subject.includes('cyber essentials') || subject.includes('iasme')) {
  category = 'ce-update';
  agent = 'marketing';
  priority = 'Medium';
  tags.push('cyber-essentials', 'linkedin-opportunity');
}

// ICO / Data Protection
else if (from.includes('ico.org') || subject.includes('data protection') || subject.includes('gdpr') || subject.includes('ico')) {
  category = 'data-protection';
  agent = 'marketing';
  priority = 'Medium';
  tags.push('gdpr', 'data-protection', 'linkedin-opportunity');
}

// Defence / MOD
else if (from.includes('gov.uk') || subject.includes('def stan') || subject.includes('defcon') || subject.includes('defence') || subject.includes('mod digital')) {
  category = 'defence-update';
  agent = 'marketing';
  priority = 'Medium';
  tags.push('defence', 'def-stan');
}

// Contracts Finder
else if (from.includes('contractsfinder') || from.includes('contracts finder') || subject.includes('contract') || subject.includes('tender') || subject.includes('procurement')) {
  category = 'procurement';
  agent = 'sales-researcher';
  priority = 'High';
  tags.push('procurement', 'prospect');
}

// ADS Group
else if (from.includes('adsgroup') || subject.includes('ads group') || subject.includes('aerospace') || subject.includes('defence supply chain')) {
  category = 'industry';
  agent = 'marketing';
  priority = 'Low';
  tags.push('industry', 'ads-group');
}

// Newsletter / general industry
else if (subject.includes('newsletter') || subject.includes('digest') || subject.includes('weekly') || subject.includes('monthly')) {
  category = 'newsletter';
  agent = 'marketing';
  priority = 'Low';
  tags.push('newsletter');
}

// Events / webinars
else if (subject.includes('event') || subject.includes('webinar') || subject.includes('conference') || subject.includes('register')) {
  category = 'event';
  agent = 'product-manager';
  priority = 'Low';
  tags.push('event');
}

const idempotencyKey = `email:${category}:${Buffer.from(subject + date).toString('base64').substring(0, 32)}`;

return [{ json: {
  category,
  agent,
  priority,
  tags,
  idempotencyKey,
  email: {
    from: raw.from || '',
    subject: raw.subject || '',
    date,
    bodyPreview: body.substring(0, 1500),
    fullBody: body,
    threadId
  }
} }];

